/**
 * Search Module - Handles all search functionality
 * Enhanced with separate search fields for each criterion
 */

const SearchModule = (function() {
    let searchResults = [];
    let cachedData = { clients: [], requests: [], cars: [] };
    
    // Search criteria object
    let searchCriteria = {
        clientName: '',
        phone: '',
        email: '',
        request: '',
        carName: ''
    };
    
    let currentFilters = { 
        type: '', 
        status: '', 
        brand: '', 
        model: '', 
        color: '', 
        category: '', 
        condition: ''
    };
    
    const debouncedSearch = App.debounce(performSearch, 300);

    // ==================== HELPER FUNCTIONS ====================
    
    /**
     * Normalize text for search (lowercase, trim)
     */
    function normalizeText(text) {
        if (!text) return '';
        return String(text).toLowerCase().trim();
    }
    
    /**
     * Normalize phone number for partial matching
     * Removes spaces, symbols, and country code prefix
     */
    function normalizePhone(phone) {
        if (!phone) return '';
        // Remove all non-digit characters
        let normalized = String(phone).replace(/\D/g, '');
        // Remove leading country code if present (keep last 10-12 digits)
        if (normalized.length > 10) {
            normalized = normalized.slice(-10);
        }
        return normalized;
    }
    
    /**
     * Check if a phone number matches a search term
     * Supports partial matching
     */
    function phoneMatches(phone, searchTerm) {
        if (!phone || !searchTerm) return false;
        
        const normalizedPhone = normalizePhone(phone);
        const normalizedSearch = normalizePhone(searchTerm);
        
        if (normalizedSearch.length === 0) return false;
        
        // Check if search term is contained in phone number
        return normalizedPhone.includes(normalizedSearch);
    }
    
    /**
     * Calculate Levenshtein distance between two strings
     * Lightweight fuzzy matching algorithm
     */
    function levenshteinDistance(str1, str2) {
        const s1 = normalizeText(str1);
        const s2 = normalizeText(str2);
        
        if (s1.length === 0) return s2.length;
        if (s2.length === 0) return s1.length;
        
        const matrix = [];
        
        for (let i = 0; i <= s2.length; i++) {
            matrix[i] = [i];
        }
        
        for (let j = 0; j <= s1.length; j++) {
            matrix[0][j] = j;
        }
        
        for (let i = 1; i <= s2.length; i++) {
            for (let j = 1; j <= s1.length; j++) {
                const cost = s2[i-1] === s1[j-1] ? 0 : 1;
                matrix[i][j] = Math.min(
                    matrix[i-1][j] + 1,
                    matrix[i][j-1] + 1,
                    matrix[i-1][j-1] + cost
                );
            }
        }
        
        return matrix[s2.length][s1.length];
    }
    
    /**
     * Fuzzy match for client names
     * First tries exact includes, then approximate matching
     */
    function fuzzyMatch(text, searchTerm) {
        if (!text || !searchTerm) return false;
        
        const normalizedText = normalizeText(text);
        const normalizedSearch = normalizeText(searchTerm);
        
        // Exact match or includes
        if (normalizedText.includes(normalizedSearch)) return true;
        
        // For short search terms, require exact match
        if (normalizedSearch.length < 3) return false;
        
        // Check if search term appears as a word boundary
        const words = normalizedText.split(/\s+/);
        if (words.some(word => word.includes(normalizedSearch))) return true;
        
        // Levenshtein distance for approximate matching
        const distance = levenshteinDistance(normalizedText, normalizedSearch);
        const maxLength = Math.max(normalizedText.length, normalizedSearch.length);
        const similarity = 1 - (distance / maxLength);
        
        // Accept if similarity is above 70%
        return similarity >= 0.7;
    }
    
    /**
     * Safe HTML escaping before highlighting
     */
    function escapeHtml(text) {
        if (!text) return '';
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }
    
    /**
     * Highlight search keywords in text
     */
    function highlightText(text, searchTerm) {
        if (!text || !searchTerm) return escapeHtml(text);
        
        const escapedText = escapeHtml(text);
        const normalizedSearch = normalizeText(searchTerm);
        
        if (normalizedSearch.length === 0) return escapedText;
        
        const regex = new RegExp(`(${normalizedSearch.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi');
        return escapedText.replace(regex, '<span class="highlight">$1</span>');
    }
    
    /**
     * Check if a client matches all search criteria
     */
    function clientMatches(client) {
        const clientName = client.name || '';
        const clientPhone = client.phone || '';
        const clientEmail = client.email || '';
        const clientNotes = client.notes || '';
        
        // Check client name
        if (searchCriteria.clientName && !fuzzyMatch(clientName, searchCriteria.clientName)) {
            return false;
        }
        
        // Check phone
        if (searchCriteria.phone && !phoneMatches(clientPhone, searchCriteria.phone)) {
            return false;
        }
        
        // Check email
        if (searchCriteria.email && !normalizeText(clientEmail).includes(normalizeText(searchCriteria.email))) {
            return false;
        }
        
        // Check request (search in client notes)
        if (searchCriteria.request && !normalizeText(clientNotes).includes(normalizeText(searchCriteria.request))) {
            return false;
        }
        
        // Check car name (clients don't have car names)
        if (searchCriteria.carName) {
            return false;
        }
        
        return true;
    }
    
    /**
     * Check if a request matches all search criteria
     */
    function requestMatches(request) {
        const title = request.title || '';
        const notes = request.notes || '';
        const clientName = request.clientName || '';
        const carData = request.carData;
        const carName = carData ? `${carData.brand || ''} ${carData.model || ''}`.trim() : '';
        
        // Check client name
        if (searchCriteria.clientName && !normalizeText(clientName).includes(normalizeText(searchCriteria.clientName))) {
            return false;
        }
        
        // Check phone (requests don't have direct phone, but can search through client)
        if (searchCriteria.phone) {
            const client = cachedData.clients.find(c => c.id == request.clientid);
            const clientPhone = client ? client.phone : '';
            if (!phoneMatches(clientPhone, searchCriteria.phone)) {
                return false;
            }
        }
        
        // Check email (requests don't have direct email, but can search through client)
        if (searchCriteria.email) {
            const client = cachedData.clients.find(c => c.id == request.clientid);
            const clientEmail = client ? client.email : '';
            if (!normalizeText(clientEmail).includes(normalizeText(searchCriteria.email))) {
                return false;
            }
        }
        
        // Check request (title or notes)
        if (searchCriteria.request) {
            const requestText = `${title} ${notes}`;
            if (!normalizeText(requestText).includes(normalizeText(searchCriteria.request))) {
                return false;
            }
        }
        
        // Check car name
        if (searchCriteria.carName && !normalizeText(carName).includes(normalizeText(searchCriteria.carName))) {
            return false;
        }
        
        return true;
    }
    
    /**
     * Check if a car matches all search criteria
     */
    function carMatches(car) {
        const carName = `${car.brand || ''} ${car.model || ''}`.trim();
        const carNotes = car.notes || '';
        
        // Check client name (cars don't have client names)
        if (searchCriteria.clientName) {
            return false;
        }
        
        // Check phone (cars don't have phone)
        if (searchCriteria.phone) {
            return false;
        }
        
        // Check email (cars don't have email)
        if (searchCriteria.email) {
            return false;
        }
        
        // Check request (search in car notes)
        if (searchCriteria.request && !normalizeText(carNotes).includes(normalizeText(searchCriteria.request))) {
            return false;
        }
        
        // Check car name
        if (searchCriteria.carName && !normalizeText(carName).includes(normalizeText(searchCriteria.carName))) {
            return false;
        }
        
        return true;
    }

    // ==================== INITIALIZATION ====================
    function init() {
        console.log('🔍 Search Module Initialized');
        bindEvents();
        loadAllData();
        setupFilterVisibility();
    }

    function bindEvents() {
        // Search input fields
        const searchClientName = document.getElementById('search-client-name');
        const searchPhone = document.getElementById('search-phone');
        const searchEmail = document.getElementById('search-email');
        const searchRequest = document.getElementById('search-request');
        const searchCarName = document.getElementById('search-car-name');
        
        if (searchClientName) {
            searchClientName.addEventListener('input', (e) => {
                searchCriteria.clientName = e.target.value;
                debouncedSearch();
            });
        }
        
        if (searchPhone) {
            searchPhone.addEventListener('input', (e) => {
                searchCriteria.phone = e.target.value;
                debouncedSearch();
            });
        }
        
        if (searchEmail) {
            searchEmail.addEventListener('input', (e) => {
                searchCriteria.email = e.target.value;
                debouncedSearch();
            });
        }
        
        if (searchRequest) {
            searchRequest.addEventListener('input', (e) => {
                searchCriteria.request = e.target.value;
                debouncedSearch();
            });
        }
        
        if (searchCarName) {
            searchCarName.addEventListener('input', (e) => {
                searchCriteria.carName = e.target.value;
                debouncedSearch();
            });
        }
        
        // Apply search button
        const applyBtn = document.getElementById('apply-search');
        if (applyBtn) {
            applyBtn.addEventListener('click', () => {
                performSearch();
            });
        }
        
        // Clear all button
        const clearBtn = document.getElementById('clear-all-search');
        if (clearBtn) {
            clearBtn.addEventListener('click', clearAllSearchFields);
        }
        
        // Type filter
        const typeFilter = document.getElementById('search-type');
        if (typeFilter) {
            typeFilter.addEventListener('change', (e) => {
                currentFilters.type = e.target.value;
                setupFilterVisibility();
                performSearch();
            });
        }
        
        // Status filter
        const statusFilter = document.getElementById('search-status');
        if (statusFilter) {
            statusFilter.addEventListener('change', (e) => {
                currentFilters.status = e.target.value;
                performSearch();
            });
        }
        
        // Car filters
        const brandFilter = document.getElementById('filter-brand');
        const modelFilter = document.getElementById('filter-model');
        const colorFilter = document.getElementById('filter-color');
        const categoryFilter = document.getElementById('filter-category');
        const conditionFilter = document.getElementById('filter-condition');
        
        if (brandFilter) {
            brandFilter.addEventListener('change', (e) => {
                currentFilters.brand = e.target.value;
                updateModelFilter();
                performSearch();
            });
        }
        
        if (modelFilter) {
            modelFilter.addEventListener('change', (e) => {
                currentFilters.model = e.target.value;
                performSearch();
            });
        }
        
        if (colorFilter) {
            colorFilter.addEventListener('change', (e) => {
                currentFilters.color = e.target.value;
                performSearch();
            });
        }
        
        if (categoryFilter) {
            categoryFilter.addEventListener('change', (e) => {
                currentFilters.category = e.target.value;
                performSearch();
            });
        }
        
        if (conditionFilter) {
            conditionFilter.addEventListener('change', (e) => {
                currentFilters.condition = e.target.value;
                performSearch();
            });
        }
        
        // Sort select
        const sortSelect = document.getElementById('search-sort');
        if (sortSelect) {
            sortSelect.addEventListener('change', (e) => {
                sortResults(e.target.value);
            });
        }
        
        // Results container click
        const resultsContainer = document.getElementById('search-results');
        if (resultsContainer) {
            resultsContainer.addEventListener('click', handleResultClick);
        }
    }
    
    function clearAllSearchFields() {
        // Clear search criteria
        searchCriteria = {
            clientName: '',
            phone: '',
            email: '',
            request: '',
            carName: ''
        };
        
        // Clear input fields
        const searchClientName = document.getElementById('search-client-name');
        const searchPhone = document.getElementById('search-phone');
        const searchEmail = document.getElementById('search-email');
        const searchRequest = document.getElementById('search-request');
        const searchCarName = document.getElementById('search-car-name');
        
        if (searchClientName) searchClientName.value = '';
        if (searchPhone) searchPhone.value = '';
        if (searchEmail) searchEmail.value = '';
        if (searchRequest) searchRequest.value = '';
        if (searchCarName) searchCarName.value = '';
        
        // Clear filters
        currentFilters = { 
            type: '', 
            status: '', 
            brand: '', 
            model: '', 
            color: '', 
            category: '', 
            condition: ''
        };
        
        const typeFilter = document.getElementById('search-type');
        const statusFilter = document.getElementById('search-status');
        const brandFilter = document.getElementById('filter-brand');
        const modelFilter = document.getElementById('filter-model');
        const colorFilter = document.getElementById('filter-color');
        const categoryFilter = document.getElementById('filter-category');
        const conditionFilter = document.getElementById('filter-condition');
        
        if (typeFilter) typeFilter.value = '';
        if (statusFilter) statusFilter.value = '';
        if (brandFilter) brandFilter.value = '';
        if (modelFilter) modelFilter.value = '';
        if (colorFilter) colorFilter.value = '';
        if (categoryFilter) categoryFilter.value = '';
        if (conditionFilter) conditionFilter.value = '';
        
        updateCarFilters();
        performSearch();
        App.showToast('All search fields cleared', 'success', 1500);
    }

    function setupFilterVisibility() {
        const carFiltersDiv = document.getElementById('car-filters');
        
        if (carFiltersDiv) {
            if (currentFilters.type === 'car' || currentFilters.type === '') {
                carFiltersDiv.style.display = 'flex';
            } else {
                carFiltersDiv.style.display = 'none';
            }
        }
    }

    // ==================== HELPER FUNCTIONS FOR FILTERS ====================
    function getUniqueValues(data, field) {
        if (!data || !Array.isArray(data)) return [];
        const values = data
            .map(item => item[field])
            .filter(value => value && value !== '' && value !== null && value !== 'undefined')
            .map(value => String(value).trim());
        return [...new Set(values)].sort();
    }

    function updateModelFilter() {
        const modelFilter = document.getElementById('filter-model');
        if (!modelFilter) return;

        const currentBrand = currentFilters.brand;
        let models = [];

        if (currentBrand && currentBrand !== '') {
            const filteredCars = cachedData.cars.filter(car => 
                car.brand && car.brand.toLowerCase() === currentBrand.toLowerCase()
            );
            models = getUniqueValues(filteredCars, 'model');
        } else {
            models = getUniqueValues(cachedData.cars, 'model');
        }

        const currentModel = currentFilters.model;
        modelFilter.innerHTML = '<option value="">All Models</option>';
        models.forEach(model => {
            const selected = currentModel === model ? 'selected' : '';
            modelFilter.innerHTML += `<option value="${App.escapeHtml(model)}" ${selected}>${App.escapeHtml(model)}</option>`;
        });
    }

    function updateCarFilters() {
        const cars = cachedData.cars || [];
        
        const brandFilter = document.getElementById('filter-brand');
        const colorFilter = document.getElementById('filter-color');
        const categoryFilter = document.getElementById('filter-category');
        const conditionFilter = document.getElementById('filter-condition');

        const brands = getUniqueValues(cars, 'brand');
        const colors = getUniqueValues(cars, 'color');
        const categories = getUniqueValues(cars, 'category');
        const conditions = getUniqueValues(cars, 'condition');

        if (brandFilter) {
            brandFilter.innerHTML = '<option value="">All Brands</option>';
            brands.forEach(brand => {
                const selected = currentFilters.brand === brand ? 'selected' : '';
                brandFilter.innerHTML += `<option value="${App.escapeHtml(brand)}" ${selected}>${App.escapeHtml(brand)}</option>`;
            });
        }

        if (colorFilter) {
            colorFilter.innerHTML = '<option value="">All Colors</option>';
            colors.forEach(color => {
                const selected = currentFilters.color === color ? 'selected' : '';
                colorFilter.innerHTML += `<option value="${App.escapeHtml(color)}" ${selected}>${App.escapeHtml(color)}</option>`;
            });
        }

        if (categoryFilter) {
            categoryFilter.innerHTML = '<option value="">All Categories</option>';
            categories.forEach(category => {
                const selected = currentFilters.category === category ? 'selected' : '';
                categoryFilter.innerHTML += `<option value="${App.escapeHtml(category)}" ${selected}>${App.escapeHtml(category)}</option>`;
            });
        }

        if (conditionFilter) {
            conditionFilter.innerHTML = '<option value="">All Conditions</option>';
            conditions.forEach(condition => {
                const selected = currentFilters.condition === condition ? 'selected' : '';
                conditionFilter.innerHTML += `<option value="${App.escapeHtml(condition)}" ${selected}>${App.escapeHtml(condition)}</option>`;
            });
        }

        updateModelFilter();
    }

    // ==================== DATA LOADING ====================
    async function loadAllData() {
        showLoading(true);
        
        try {
            const [clients, requests, cars] = await Promise.all([
                API.getClients().catch(() => []),
                API.getRequests().catch(() => []),
                API.getCars().catch(() => [])
            ]);
            
            cachedData = { clients, requests, cars };
            
            updateCarFilters();
            
            await performSearch();
        } catch (error) {
            console.error('Error loading data:', error);
            showEmptyState('Error loading data');
        } finally {
            showLoading(false);
        }
    }

    // ==================== SEARCH FUNCTIONALITY ====================
    async function performSearch() {
        try {
            let allItems = [
                ...cachedData.clients.map(item => ({ ...item, _type: 'client' })),
                ...cachedData.requests.map(item => {
                    const client = cachedData.clients.find(c => c.id == item.clientid);
                    const car = cachedData.cars.find(c => c.id == item.carid);
                    return {
                        ...item,
                        clientName: client ? client.name : 'Unknown',
                        carData: car || null,
                        _type: 'request'
                    };
                }),
                ...cachedData.cars.map(item => ({ ...item, _type: 'car' }))
            ];
            
            // Apply search criteria
            const hasSearchCriteria = Object.values(searchCriteria).some(value => value && value.trim() !== '');
            
            if (hasSearchCriteria) {
                allItems = allItems.filter(item => {
                    if (item._type === 'client') {
                        return clientMatches(item);
                    } else if (item._type === 'request') {
                        return requestMatches(item);
                    } else if (item._type === 'car') {
                        return carMatches(item);
                    }
                    return false;
                });
            }
            
            // Apply type filter
            if (currentFilters.type) {
                allItems = allItems.filter(item => item._type === currentFilters.type);
            }
            
            // Apply status filter (only for requests)
            if (currentFilters.status) {
                allItems = allItems.filter(item => 
                    item._type === 'request' && item.status === currentFilters.status
                );
            }
            
            // Apply car filters
            if (currentFilters.brand || currentFilters.model || currentFilters.color || 
                currentFilters.category || currentFilters.condition) {
                allItems = allItems.filter(item => {
                    let carToCheck = null;
                    
                    if (item._type === 'car') {
                        carToCheck = item;
                    } else if (item._type === 'request' && item.carData) {
                        carToCheck = item.carData;
                    } else {
                        return true;
                    }
                    
                    if (!carToCheck) return true;
                    
                    // Brand filter
                    if (currentFilters.brand && currentFilters.brand !== '') {
                        const carBrand = (carToCheck.brand || '').toLowerCase();
                        const filterBrand = currentFilters.brand.toLowerCase();
                        if (carBrand !== filterBrand) return false;
                    }
                    
                    // Model filter
                    if (currentFilters.model && currentFilters.model !== '') {
                        const carModel = (carToCheck.model || '').toLowerCase();
                        const filterModel = currentFilters.model.toLowerCase();
                        if (carModel !== filterModel) return false;
                    }
                    
                    // Color filter
                    if (currentFilters.color && currentFilters.color !== '') {
                        const carColor = (carToCheck.color || '').toLowerCase();
                        const filterColor = currentFilters.color.toLowerCase();
                        if (carColor !== filterColor) return false;
                    }
                    
                    // Category filter
                    if (currentFilters.category && currentFilters.category !== '') {
                        const carCategory = (carToCheck.category || '').toLowerCase();
                        const filterCategory = currentFilters.category.toLowerCase();
                        if (carCategory !== filterCategory) return false;
                    }
                    
                    // Condition filter
                    if (currentFilters.condition && currentFilters.condition !== '') {
                        const carCondition = (carToCheck.condition || '').toLowerCase();
                        const filterCondition = currentFilters.condition.toLowerCase();
                        if (carCondition !== filterCondition) return false;
                    }
                    
                    return true;
                });
            }
            
            searchResults = allItems;
            updateResultsCount();
            
            const sortSelect = document.getElementById('search-sort');
            if (sortSelect && sortSelect.value !== 'relevance') {
                sortResults(sortSelect.value, false);
            } else {
                displayResults();
            }
        } catch (error) {
            console.error('Search error:', error);
            showEmptyState('An error occurred during search');
        }
    }

    // ==================== SORTING ====================
    function sortResults(sortBy, refreshDisplay = true) {
        const getName = (item) => {
            switch (item._type) {
                case 'client': return item.name || '';
                case 'request': return item.title || '';
                case 'car': return `${item.brand || ''} ${item.model || ''}`;
                default: return '';
            }
        };

        const getDate = (item) => {
            switch (item._type) {
                case 'client': return item.registeredat || item.registeredAt || '';
                case 'request': return item.createdAt || item.createdat || '';
                case 'car': return item.createdAt || item.createdat || '';
                default: return '';
            }
        };

        switch (sortBy) {
            case 'name_asc':
                searchResults.sort((a, b) => getName(a).localeCompare(getName(b)));
                break;
            case 'name_desc':
                searchResults.sort((a, b) => getName(b).localeCompare(getName(a)));
                break;
            case 'date_new':
                searchResults.sort((a, b) => {
                    const dateA = new Date(getDate(a) || 0);
                    const dateB = new Date(getDate(b) || 0);
                    return dateB - dateA;
                });
                break;
            case 'date_old':
                searchResults.sort((a, b) => {
                    const dateA = new Date(getDate(a) || 0);
                    const dateB = new Date(getDate(b) || 0);
                    return dateA - dateB;
                });
                break;
            default:
                break;
        }

        if (refreshDisplay) {
            displayResults();
        } else {
            displayResults();
        }
    }

    // ==================== DISPLAY RESULTS ====================
    function updateResultsCount() {
        const countElement = document.getElementById('search-results-count');
        if (countElement) {
            countElement.textContent = `Search Results (${searchResults.length})`;
        }
    }

    function displayResults() {
        const container = document.getElementById('search-results');
        if (!container) return;

        if (searchResults.length === 0) {
            const hasCriteria = Object.values(searchCriteria).some(v => v && v.trim() !== '');
            showEmptyState(hasCriteria ? 'No results found' : 'Enter search criteria to find clients, requests, or cars');
            return;
        }

        const grouped = {
            client: searchResults.filter(item => item._type === 'client'),
            request: searchResults.filter(item => item._type === 'request'),
            car: searchResults.filter(item => item._type === 'car')
        };

        let html = '';

        if (grouped.client.length > 0) {
            html += '<div class="search-type-header"><h4><i class="fa-solid fa-users"></i> Clients (' + grouped.client.length + ')</h4></div>';
            grouped.client.forEach(item => {
                html += createClientResult(item);
            });
        }

        if (grouped.request.length > 0) {
            html += '<div class="search-type-header"><h4><i class="fa-solid fa-file-lines"></i> Requests (' + grouped.request.length + ')</h4></div>';
            grouped.request.forEach(item => {
                html += createRequestResult(item);
            });
        }

        if (grouped.car.length > 0) {
            html += '<div class="search-type-header"><h4><i class="fa-solid fa-car"></i> Cars (' + grouped.car.length + ')</h4></div>';
            grouped.car.forEach(item => {
                html += createCarResult(item);
            });
        }

        container.innerHTML = html;
    }

    function createClientResult(item) {
        const highlightedName = highlightText(item.name || 'Unnamed Client', searchCriteria.clientName);
        const highlightedPhone = item.phone && item.phone !== 'No phone' ? highlightText(item.phone, searchCriteria.phone) : (item.phone || 'No phone number');
        const highlightedEmail = item.email && item.email !== 'No email' ? highlightText(item.email, searchCriteria.email) : '';
        const highlightedNotes = item.notes ? highlightText(item.notes, searchCriteria.request) : '';
        
        return `
            <div class="search-result-item" data-type="client" data-id="${App.escapeHtml(item.id)}">
                <div class="search-result-icon"><i class="fa-solid fa-user"></i></div>
                <div class="search-result-content">
                    <div class="search-result-title">${highlightedName}</div>
                    <div class="search-result-subtitle">
                        <i class="fa-solid fa-phone"></i> ${highlightedPhone}
                    </div>
                    ${highlightedEmail ? `
                    <div class="search-result-subtitle">
                        <i class="fa-solid fa-envelope"></i> ${highlightedEmail}
                    </div>
                    ` : ''}
                    ${highlightedNotes ? `
                    <div class="search-result-notes">
                        <i class="fa-regular fa-note-sticky"></i> ${App.truncateText(highlightedNotes, 60)}
                    </div>
                    ` : ''}
                </div>
                <div class="search-result-action">
                    <i class="fa-solid fa-chevron-left"></i>
                </div>
            </div>
        `;
    }

    function createRequestResult(item) {
        const status = item.status || 'pending';
        const statusText = status === 'active' ? 'Active' : status === 'pending' ? 'Pending' : 'Completed';
        const statusIcon = status === 'active' ? 'fa-play-circle' : status === 'pending' ? 'fa-clock' : 'fa-check-circle';
        
        const highlightedTitle = highlightText(item.title || 'Untitled Request', searchCriteria.request);
        const highlightedClientName = highlightText(item.clientName || 'Unknown', searchCriteria.clientName);
        const highlightedNotes = item.notes ? highlightText(item.notes, searchCriteria.request) : '';
        
        const carName = item.carData ? `${item.carData.brand || ''} ${item.carData.model || ''}`.trim() : 'No car';
        const highlightedCarName = highlightText(carName, searchCriteria.carName);
        
        return `
            <div class="search-result-item" data-type="request" data-id="${App.escapeHtml(item.id)}">
                <div class="search-result-icon"><i class="fa-solid fa-file-lines"></i></div>
                <div class="search-result-content">
                    <div class="search-result-title">${highlightedTitle}</div>
                    <div class="search-result-subtitle">
                        <i class="fa-solid fa-user"></i> ${highlightedClientName}
                    </div>
                    <div class="search-result-subtitle">
                        <i class="fa-solid fa-car"></i> ${highlightedCarName}
                    </div>
                    ${highlightedNotes ? `
                    <div class="search-result-notes">
                        <i class="fa-regular fa-note-sticky"></i> ${App.truncateText(highlightedNotes, 60)}
                    </div>
                    ` : ''}
                    <div class="search-result-status">
                        <span class="status status-${status}">
                            <i class="fa-solid ${statusIcon}"></i>
                            ${statusText}
                        </span>
                    </div>
                </div>
                <div class="search-result-action">
                    <i class="fa-solid fa-chevron-left"></i>
                </div>
            </div>
        `;
    }

    function createCarResult(item) {
        const conditionDisplay = App.formatCondition(item.condition);
        const carName = `${item.brand || ''} ${item.model || ''}`.trim();
        const highlightedCarName = highlightText(carName, searchCriteria.carName);
        const highlightedNotes = item.notes ? highlightText(item.notes, searchCriteria.request) : '';
        
        return `
            <div class="search-result-item" data-type="car" data-id="${App.escapeHtml(item.id)}">
                <div class="search-result-icon"><i class="fa-solid fa-car"></i></div>
                <div class="search-result-content">
                    <div class="search-result-title">${highlightedCarName} (${App.escapeHtml(item.year || '')})</div>
                    <div class="search-result-subtitle">
                        <span><i class="fa-solid fa-tag"></i> ${App.escapeHtml(item.category || 'Not specified')}</span>
                        <span><i class="fa-solid fa-palette"></i> ${App.escapeHtml(item.color || 'Not specified')}</span>
                        <span><i class="fa-solid fa-clipboard-check"></i> ${App.escapeHtml(conditionDisplay)}</span>
                    </div>
                    <div class="search-result-notes">
                        <i class="fa-solid fa-dollar-sign"></i> ${item.price ? App.formatPrice(item.price) : 'Price on request'}
                    </div>
                    ${highlightedNotes ? `
                    <div class="search-result-notes">
                        <i class="fa-regular fa-note-sticky"></i> ${App.truncateText(highlightedNotes, 60)}
                    </div>
                    ` : ''}
                </div>
                <div class="search-result-action">
                    <i class="fa-solid fa-chevron-left"></i>
                </div>
            </div>
        `;
    }

    // ==================== CLICK HANDLER ====================
    function handleResultClick(e) {
        const resultItem = e.target.closest('.search-result-item');
        if (!resultItem) return;

        const type = resultItem.dataset.type;
        const id = resultItem.dataset.id;

        if (!type || !id) return;

        sessionStorage.setItem('viewItem', JSON.stringify({ type, id }));
        
        App.showToast(`Loading details...`, 'info', 1000);
        
        const page = type === 'client' ? 'index.html' : type === 'request' ? 'requests.html' : 'cars.html';
        window.location.href = page;
    }

    // ==================== UI STATES ====================
    function showLoading(show) {
        const container = document.getElementById('search-results');
        const countElement = document.getElementById('search-results-count');
        
        if (!container) return;

        if (show) {
            if (countElement) countElement.textContent = 'Searching...';
            container.innerHTML = `
                <div class="search-loading">
                    <div class="loading-spinner">
                        <div class="spinner"></div>
                        <p>Loading data...</p>
                    </div>
                </div>
            `;
        }
    }

    function showEmptyState(message) {
        const container = document.getElementById('search-results');
        const countElement = document.getElementById('search-results-count');
        
        if (!container) return;
        
        if (countElement) countElement.textContent = 'Search Results (0)';

        container.innerHTML = `
            <div class="empty-search-state">
                <i class="fa-solid fa-magnifying-glass"></i>
                <p>${App.escapeHtml(message)}</p>
            </div>
        `;
    }

    function checkStoredItem() {
        const stored = sessionStorage.getItem('viewItem');
        if (stored) {
            try {
                const { type, id } = JSON.parse(stored);
                sessionStorage.removeItem('viewItem');
                
                setTimeout(() => {
                    if (type === 'client' && window.ClientsModule) {
                        ClientsModule.viewClientDetails(id);
                    } else if (type === 'request' && window.RequestsModule) {
                        RequestsModule.loadRequestDetails(id);
                    } else if (type === 'car' && window.CarsModule) {
                        CarsModule.viewCarDetails(id);
                    }
                }, 300);
            } catch (e) {
                console.error('Error parsing stored item:', e);
            }
        }
    }

    return {
        init,
        refreshData: loadAllData,
        performSearch,
        checkStoredItem
    };
})();

window.SearchModule = SearchModule;

document.addEventListener('DOMContentLoaded', () => {
    if (document.getElementById('search-screen')) {
        SearchModule.init();
        SearchModule.checkStoredItem();
    }
});